      <template v-if="step === 'Sign up'">
        <UiTextInput v-model="authForm.email" placeholder="Enter your email" />
        <UiPasswordInput v-model="authForm.password" placeholder="Create password" />
        <UiPasswordInput v-model="authForm.confirmPassword" placeholder="Confirm password" />
        <UiButton variant="neutral" size="m" @click="goToStep('Enter your security code')">Sign up</UiButton>
        <div class="caption-2">
          Already have an account? 
          <button 
