<script setup lang="ts">
type StepsTypes = 'Sign up' | 'Sign in' | 'Enter your security code'

const step = ref<StepsTypes>('Sign up') 
const codeLength = 4

const initialState = {
  email: '',
  password: '',
  confirmPassword: '',
  code: ''
}

const authForm = ref({...initialState})

const goToStep = (v: StepsTypes) => {
  authForm.value = { ...initialState }
  step.value = v
}
</script>

